/* ── Flashcards Exercise ──────────────────────────────────────────── */

function FlashcardsExercise({ data, onComplete }) {
  const tarjetas = data.tarjetas || []
  const [current, setCurrent] = useState(0)
  const [flipped, setFlipped] = useState(false)
  const [results, setResults] = useState([])

  function rate(difficulty) {
    // Easy=100, Medium=60, Hard=20
    const score = difficulty === 'easy' ? 100 : difficulty === 'medium' ? 60 : 20
    setResults((r) => [...r, score])
    setFlipped(false)
    if (current + 1 < tarjetas.length) {
      setCurrent(current + 1)
    } else {
      const allResults = [...results, score]
      const avg = Math.round(allResults.reduce((a, b) => a + b, 0) / allResults.length)
      onComplete(avg)
    }
  }

  if (!tarjetas[current]) return null
  const card = tarjetas[current]

  return (
    <div>
      <p className="text-sm text-gray-500 dark:text-gray-400 mb-2">{data.instrucciones}</p>
      <p className="text-xs text-gray-400 dark:text-gray-500 mb-4">Tarjeta {current + 1} de {tarjetas.length}</p>

      {/* Card */}
      <button
        onClick={() => setFlipped(!flipped)}
        className="w-full min-h-[200px] card hover:shadow-lg transition-all flex flex-col items-center justify-center text-center p-8 mb-4"
      >
        {!flipped ? (
          <>
            <p className="text-2xl font-bold text-gray-800 dark:text-gray-100">{card.frente}</p>
            <p className="text-xs text-gray-400 mt-4">Toca para voltear →</p>
          </>
        ) : (
          <>
            <p className="text-xl font-semibold text-primary-600 dark:text-primary-400">{card.reverso}</p>
            {card.ejemplo && (
              <p className="text-sm text-gray-500 dark:text-gray-400 mt-3 italic">"{card.ejemplo}"</p>
            )}
          </>
        )}
      </button>

      {/* Rating buttons (only after flip) */}
      {flipped && (
        <div className="grid grid-cols-3 gap-3">
          <button onClick={() => rate('hard')} className="py-3 rounded-xl bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 font-semibold hover:bg-red-200 dark:hover:bg-red-900/50 transition-colors">
            😣 Difícil
          </button>
          <button onClick={() => rate('medium')} className="py-3 rounded-xl bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 font-semibold hover:bg-amber-200 dark:hover:bg-amber-900/50 transition-colors">
            🤔 Medio
          </button>
          <button onClick={() => rate('easy')} className="py-3 rounded-xl bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 font-semibold hover:bg-green-200 dark:hover:bg-green-900/50 transition-colors">
            😊 Fácil
          </button>
        </div>
      )}
    </div>
  )
}

/* ── Main LessonExercise Page ─────────────────────────────────────── */

export default function LessonExercise() {
  const { id } = useParams()
  const location = useLocation()
  const navigate = useNavigate()
  const { dark, toggle } = useTheme()

  const [lesson, setLesson] = useState(location.state?.lesson || null)
  const [loading, setLoading] = useState(!lesson)
  const [completed, setCompleted] = useState(false)
  const [score, setScore] = useState(0)
  const [saving, setSaving] = useState(false)

  // Fetch lesson if not passed via navigation state
  useEffect(() => {
    if (!lesson) {
      api.get('/api/leccion/lista').then(({ data }) => {
        const found = data.find((l) => l.id === parseInt(id))
        if (found) setLesson(found)
        setLoading(false)
      }).catch(() => setLoading(false))
    }
  }, [id, lesson])

  const exerciseData = useMemo(() => {
    if (!lesson) return null
    try {
      return JSON.parse(lesson.contenido)
    } catch {
      return null
    }
  }, [lesson])

  const handleComplete = useCallback(async (finalScore) => {
    setScore(finalScore)
    setCompleted(true)
    setSaving(true)
    try {
      await api.post(`/api/leccion/${lesson.id}/completar`, {
        puntuacion: finalScore,
        resultado_json: JSON.stringify({ score: finalScore }),
      })
    } catch {
      // Lesson may already be completed
    } finally {
      setSaving(false)
    }
  }, [lesson])

  function sendToChatTutor() {
    navigate('/chat', {
      state: {
        lesson: { ...lesson, puntuacion: score },
        autoSend: true,
      },
    })
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-surface-light dark:bg-surface-dark flex items-center justify-center">
        <span className="text-gray-400">Cargando lección…</span>
      </div>
    )
  }

  if (!lesson || !exerciseData) {
    return (
      <div className="min-h-screen bg-surface-light dark:bg-surface-dark flex flex-col items-center justify-center gap-4">
        <p className="text-gray-500 dark:text-gray-400">No se pudo cargar la lección.</p>
        <button onClick={() => navigate('/dashboard')} className="btn-primary">Volver al Dashboard</button>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-surface-light dark:bg-surface-dark transition-colors duration-300">
      {/* Header */}
      <header className="bg-card-light dark:bg-card-dark shadow-sm dark:shadow-black/20 sticky top-0 z-10 transition-colors duration-300">
        <div className="max-w-3xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={() => navigate('/dashboard')} className="text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors" aria-label="Volver">
              ←
            </button>
            <img src="/logo.jpg" alt="PolyIA" className="w-8 h-8 rounded-full object-cover" />
            <div>
              <h1 className="text-sm font-bold text-primary-600 dark:text-primary-400 truncate max-w-[200px] sm:max-w-none">{lesson.tema}</h1>
              <p className="text-xs text-gray-400 dark:text-gray-500">{lesson.nivel} · {lesson.tipo_ejercicio.replace('_', ' ')}</p>
            </div>
          </div>
          <button onClick={toggle} className="p-1.5 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors" aria-label="Cambiar tema">
            {dark ? '☀️' : '🌙'}
          </button>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-8">
        {/* ── Completed screen ── */}
        {completed ? (
          <div className="card text-center py-12 space-y-4">
            <span className="text-6xl">{score >= 80 ? '🎉' : score >= 50 ? '👍' : '💪'}</span>
            <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-100">
              {score >= 80 ? '¡Excelente!' : score >= 50 ? '¡Buen trabajo!' : '¡Sigue practicando!'}
            </h2>
            <p className="text-4xl font-bold text-primary-600 dark:text-primary-400">{score}%</p>
            {saving && <p className="text-sm text-gray-400">Guardando progreso…</p>}

            <div className="flex flex-col sm:flex-row gap-3 justify-center pt-4">
              <button onClick={() => navigate('/dashboard')} className="btn-primary">
                ← Volver al Dashboard
              </button>
              <button onClick={sendToChatTutor} className="px-5 py-2.5 rounded-xl border border-primary-500 text-primary-600 dark:text-primary-400 font-semibold hover:bg-primary-50 dark:hover:bg-primary-900/30 transition-colors">
                🤖 Enviar al Chat Tutor
              </button>
            </div>
          </div>
        ) : lesson.completada ? (
          /* Already completed lesson — show read-only info */
          <div className="card text-center py-12 space-y-4">
            <span className="text-6xl">✅</span>
            <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-100">Lección ya completada</h2>
            <p className="text-4xl font-bold text-primary-600 dark:text-primary-400">{lesson.puntuacion}%</p>
            <button onClick={() => navigate('/dashboard')} className="btn-primary">← Volver al Dashboard</button>
          </div>
        ) : (
          /* ── Active exercise ── */
          <div className="card">
            {lesson.tipo_ejercicio === 'matching' && (
              <MatchingExercise data={exerciseData} onComplete={handleComplete} />
            )}
            {lesson.tipo_ejercicio === 'syntax_sorting' && (
              <SyntaxSortingExercise data={exerciseData} onComplete={handleComplete} />
            )}
            {lesson.tipo_ejercicio === 'multiple_choice' && (
              <MultipleChoiceExercise data={exerciseData} onComplete={handleComplete} idioma={lesson.idioma} />
            )}
            {lesson.tipo_ejercicio === 'categorization' && (
              <CategorizationExercise data={exerciseData} onComplete={handleComplete} />
            )}
            {lesson.tipo_ejercicio === 'fill_blank' && (
              <FillBlankExercise data={exerciseData} onComplete={handleComplete} idioma={lesson.idioma} />
            )}
            {lesson.tipo_ejercicio === 'translation' && (
              <TranslationExercise data={exerciseData} onComplete={handleComplete} />
            )}
            {lesson.tipo_ejercicio === 'dictation' && (
              <DictationExercise data={exerciseData} idioma={lesson.idioma} onComplete={handleComplete} />
            )}
            {lesson.tipo_ejercicio === 'flashcards' && (
              <FlashcardsExercise data={exerciseData} onComplete={handleComplete} />
            )}
          </div>
        )}
      </main>
    </div>
  )
}
